const fmt = $('Build Monitor Req').item.json.fmt;
const chatId = $('Build Monitor Req').item.json.chat_id;
const inputJson = $input.first().json;

// Fetch Monitor Data returns {data: "<json string>"} when responseFormat=text
// Fetch Status returns the row object directly from Management API
let raw;
if (typeof inputJson.data === 'string') {
  try { raw = JSON.parse(inputJson.data); } catch(e) { raw = []; }
} else {
  raw = Array.isArray(inputJson) ? inputJson : [inputJson];
}

const ts = (str) => {
  if (!str) return 'never';
  try { return new Date(str).toISOString().replace('T',' ').slice(0,16)+' UTC'; }
  catch(e) { return str||'?'; }
};
const sid = (id) => id ? String(id).slice(0,8) : '?';

let text = '';

if (fmt === 'status') {
  const r = Array.isArray(raw) ? raw[0] : raw;
  const paused = r.global_pause==='true'||r.global_pause===true;
  text = `\ud83d\udcca Claudis OS Status\n\nSystem: ${paused?'\u23f8\ufe0f PAUSED':'\u2705 Running'}\nClaudis: ${r.sentinel_version||'?'}\nLast activity: ${ts(r.last_audit_at)}\n\n\ud83d\udce5 Work queue: ${r.wq_pending??0} pending\n\ud83d\udd34 Errors: ${r.errors_unresolved??0} unresolved\n\ud83d\udcec Inbox: ${r.inbox_pending??0} awaiting\n\n\ud83e\udd16 Agents: ${r.agents_protected??0} protected, ${r.agents_unprotected??0} unprotected`;
}

else if (fmt === 'agents') {
  if (!raw.length) { text = '\u26a0\ufe0f No agents found.'; }
  else {
    const prot = raw.filter(a=>a.protected);
    const actv = raw.filter(a=>!a.protected&&a.status==='active');
    const rest = raw.filter(a=>!a.protected&&a.status!=='active');
    let lines = ['\ud83e\udd16 Agent Registry\n'];
    if (prot.length) { lines.push('\ud83d\udd12 Protected:'); prot.forEach(a=>lines.push(`  ${a.agent_name} \u2014 ${a.status}`)); }
    if (actv.length) { lines.push('\n\u2705 Active:'); actv.forEach(a=>lines.push(`  ${a.agent_name}`)); }
    if (rest.length) { lines.push('\n\u23f8\ufe0f Paused:'); rest.forEach(a=>lines.push(`  ${a.agent_name}`)); }
    text = lines.join('\n');
  }
}

else if (fmt === 'errors') {
  if (!raw.length) { text = '\u2705 No unresolved errors.'; }
  else {
    let lines = [`\ud83d\udd34 Unresolved Errors (${raw.length})\n`];
    raw.forEach(e => {
      lines.push(`[${ts(e.timestamp).slice(5,16)}] ${e.workflow_name||'unknown'}`);
      lines.push(`  ${e.error_type||''}: ${(e.error_message||'').slice(0,80)}`);
    });
    text = lines.join('\n');
  }
}

else if (fmt === 'inbox') {
  if (!raw.length) { text = '\ud83d\udced Inbox is empty \u2014 no pending items.'; }
  else {
    const pE = {urgent:'\ud83d\udd34',high:'\ud83d\udfe0',normal:'\ud83d\udfe1',low:'\u26aa'};
    let lines = [`\ud83d\udcec Inbox (${raw.length} pending)\n`];
    raw.forEach(i => {
      lines.push(`${pE[i.priority]||'\u26aa'} ${sid(i.id)} | ${i.message_type} | ${i.from_agent}`);
      lines.push(`  ${i.subject||'(no subject)'}`);
    });
    lines.push('\nUse: /approve <id>  /deny <id>  /reply <id> <msg>');
    text = lines.join('\n');
  }
}

else if (fmt === 'activity') {
  if (!raw.length) { text = '\ud83d\udccb No activity in the last 24 hours.'; }
  else {
    const counts = {};
    raw.forEach(e => { if(e.action) counts[e.action]=(counts[e.action]||0)+1; });
    const sorted = Object.entries(counts).sort((a,b)=>b[1]-a[1]).slice(0,8);
    let lines = ['\ud83d\udccb Activity (last 20)\n'];
    if (sorted.length) { lines.push('By type:'); sorted.forEach(([a,c])=>lines.push(`  ${a}: ${c}`)); }
    lines.push('\nRecent:');
    raw.slice(0,5).forEach(e=>lines.push(`  [${ts(e.timestamp).slice(5,16)}] ${e.action} \u2014 ${e.actor||'?'}`));
    text = lines.join('\n');
  }
}

else if (fmt === 'queue') {
  const pending = raw.filter(t=>t.status==='pending');
  const inProg  = raw.filter(t=>t.status==='claimed'||t.status==='in_progress');
  if (!pending.length && !inProg.length) { text = '\u2705 Work queue is empty.'; }
  else {
    let lines = [`\ud83d\uddc2\ufe0f Work Queue (${pending.length} pending, ${inProg.length} in progress)\n`];
    pending.forEach(t => {
      const sum = t.input_data ? JSON.stringify(t.input_data).slice(0,60) : '';
      lines.push(`[${sid(t.id)}] ${t.task_type}`);
      if (sum) lines.push(`  ${sum}`);
    });
    text = lines.join('\n');
  }
}

else if (fmt === 'outputs') {
  if (!raw.length) { text = '\ud83d\udcca No agent outputs in the last 24 hours.'; }
  else {
    let lines = [`\ud83d\udce4 Recent Outputs (${raw.length})\n`];
    raw.forEach(o => {
      lines.push(`[${ts(o.created_at).slice(5,16)}] ${o.agent_name} \u2014 ${o.output_type||'?'}`);
      const cStr = o.content ? JSON.stringify(o.content).slice(0,60) : '';
      if (cStr) lines.push(`  ${cStr}`);
    });
    text = lines.join('\n');
  }
}

else if (fmt === 'lessons') {
  if (!raw.length) { text = '\u{1F4DA} No lessons recorded yet.'; }
  else {
    let lines = ['\u{1F4DA} Top Lessons Learned\n'];
    raw.forEach(l => {
      const pct = l.confidence != null ? Math.round(l.confidence * 100) + '%' : '?%';
      const applied = l.times_applied != null ? l.times_applied : 0;
      lines.push(`\u2022 ${l.title || '(untitled)'}`);
      lines.push(`  ${l.category || 'general'} | confidence: ${pct} | applied: ${applied}x`);
    });
    text = lines.join('\n');
  }
}

else if (fmt === 'capabilities') {
  if (!raw.length) { text = '\u26A1 No capabilities recorded yet.'; }
  else {
    let lines = ['\u26A1 Capabilities\n'];
    raw.forEach(c => {
      const pct = c.confidence != null ? Math.round(c.confidence * 100) + '%' : '?%';
      const used = c.times_used != null ? c.times_used : 0;
      lines.push(`\u2022 ${c.name || '(unnamed)'}`);
      lines.push(`  ${c.category || 'general'} | confidence: ${pct} | used: ${used}x`);
    });
    text = lines.join('\n');
  }
}

else if (fmt === 'gh') {
  text = (raw && typeof raw.text === 'string') ? raw.text : JSON.stringify(raw).slice(0,500);
}

else if (fmt === 'awake') {
  const kv = {};
  (Array.isArray(raw) ? raw : [raw]).forEach(r => { if(r.key) kv[r.key]=r.value; });
  const task = kv.claudis_current_task || 'unknown';
  const beat = kv.claudis_heartbeat_at;
  const paused = kv.global_pause === 'true';
  const idle = !beat || task === 'idle';
  const age = beat ? Math.round((Date.now()-new Date(beat).getTime())/60000) : null;
  const ageStr = age !== null ? (age < 2 ? 'just now' : age + ' min ago') : 'never';
  if (paused) text = '⏸️ Claudis is PAUSED\n\nUse /resume to restart.';
  else if (idle) text = `💤 Claudis is idle\nLast seen: ${ageStr}\n\nSend /wake to start a session.`;
  else text = `🟢 Claudis is AWAKE\nTask: ${task}\nHeartbeat: ${ageStr}\n\nUse /wake only if you need to add urgent context.`;
}

else if (fmt === 'summary') {
  const tasks = raw.filter(r => r.row_type === 'task');
  const lessons = raw.filter(r => r.row_type === 'lesson');
  const lines = ['\ud83d\udccb *Claudis Summary*\n'];
  if (tasks.length) {
    lines.push('\u2705 *Recent tasks:*');
    tasks.forEach(t => {
      const when = ts(t.ts).slice(5,16);
      lines.push(`  ${when} \u2014 ${t.name}`);
    });
  } else {
    lines.push('\u2705 No completed tasks found.');
  }
  lines.push('');
  if (lessons.length) {
    lines.push('\ud83d\udcda *Recent lessons:*');
    lessons.forEach(l => lines.push(`  [${l.extra||'?'}] ${l.name}`));
  } else {
    lines.push('\ud83d\udcda No recent lessons.');
  }
  text = lines.join('\n');
}

else { text = `Response: ${JSON.stringify(raw).slice(0,200)}`; }


// Truncate to Telegram's 4096 char limit (leave buffer for emoji/overhead)
const MAX_LEN = 4000;
if (text.length > MAX_LEN) {
  text = text.slice(0, MAX_LEN) + '\n… (truncated)';
}

return [{ json: { text, chat_id: chatId } }];

